// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check title popup', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check title popup', async function() {
    await driver.get("http://localhost:4200/admin-user/list-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-control-input-content")).click();
    await driver.findElement(By.css(".main_button > span")).click();
    await driver.findElement(By.css(".ant-table-row:nth-child(1) .ant-space-item:nth-child(2) path")).click();
    await driver.findElement(By.css("#\\3Ar1\\3A > .ant-typography")).click();
    await driver.findElement(By.css("#\\3Ar1\\3A > .ant-typography")).click();
    {
      const element = await driver.findElement(By.css("#\\3Ar1\\3A > .ant-typography"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }
    assert(await driver.findElement(By.css("#\\3Ar1\\3A > .ant-typography")).getText() == "確認");
  });
});
